(function () {
    'use strict';

    // array - 数组

    // 创建数组，数组元素支持数据类型的多样性
    console.log(Array.of(1, 2, 3)); // [1, 2, 3]
    console.log(Array.of(1, "2", true)); // [1, "2", true]
    console.log(Array.of()); // []
    console.log(Array.from([1, 2, 3])); // [1, 2, 3]
    // 空位为 undefined
    console.log(Array.from([1, , 3])); // [1, undefined, 3]


    // 通过 mapFn 处理每个元素后再放入数组
    console.log(Array.from([1, 2, 3], (n) => n * 3));
    // [3, 6, 9]


    let myObj = {
        do: function(n) {
            return n * 3;
        }
    };
    // 通过 mapFn 处理每个元素后再放入数组
    // Array.from(arrayLike[, mapFn[, thisArg]])
    // mapFn 的第 2 个参数，即 thisArg 用于指定 mapFn 执行时的 this 对象
    console.log(Array.from([1, 2, 3], function (n) {
        // 这里的 this 指向的是 mapFunction 对象
        return this.do(n);
    }, myObj));
    // [3, 6, 9]


    // 对象转数组
    // 对象的属性名必须是整型（数组会自动按属性名排序），必须有 length 属性
    let a = Array.from({
        0: "1",
        2: 3,
        1: "2",
        length: 3
    });
    console.log(a);
    // ["1", "2", 3]


    // map 转 array
    console.log(Array.from(new Map([["a", "aaa"], ["b", "bbb"], ["c", "ccc"]]))); // [["a", "aaa"], ["b", "bbb"], ["c", "ccc"]]
    // set 转 array
    console.log(Array.from(new Set(["1", "2", "3"]))); // ["1", "2", "3"]
    // string 转 array
    console.log(Array.from("webabcd")); // ["w", "e", "b", "a", "b", "c", "d"]



    // 要写 filter

}());
